function installZoomControls(){$('editor-zoom-out').onclick=()=>{layout.editorZoom=constrain(layout.editorZoom-.1,.7,1.7);applyLayout({persist:true})};$('editor-zoom-in').onclick=()=>{layout.editorZoom=constrain(layout.editorZoom+.1,.7,1.7);applyLayout({persist:true})};const changePdfZoom=delta=>{const panel=document.querySelector('.preview-panel');const progress=panel.scrollHeight>panel.clientHeight?panel.scrollTop/(panel.scrollHeight-panel.clientHeight):0;layout.pdfZoom=constrain(layout.pdfZoom+delta,.55,2);applyLayout({persist:true});panel.scrollTop=progress*Math.max(0,panel.scrollHeight-panel.clientHeight);schedulePdfPageIndicatorUpdate()};$('pdf-zoom-out').onclick=()=>changePdfZoom(-.1);$('pdf-zoom-in').onclick=()=>changePdfZoom(.1)}
async function syncPdfToSource(page,x,y){if(!renderedSynctex)return;try{const response=await fetch('/api/synctex',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({page,x,y,synctex_base64:renderedSynctex})});const result=await response.json();if(!response.ok)throw new Error(result.error||'SyncTeX 위치 검색 실패');const candidates=[`paper/${result.file}`,result.file,...Object.keys(state.files).filter(path=>path.endsWith(`/${result.file}`))];const file=candidates.find(path=>state.files[path]!==undefined);if(!file)throw new Error(`${result.file} 파일을 프로젝트에서 찾지 못했습니다.`);state.files[state.current]=$('editor').value;state.current=file;setEditor();listFiles();const editor=$('editor');const lines=editor.value.split('\n');const line=Math.max(1,Math.min(result.line,lines.length));const start=lines.slice(0,line-1).reduce((total,value)=>total+value.length+1,0);const end=start+lines[line-1].length;editor.focus();editor.setSelectionRange(start,end);const lineHeight=parseFloat(getComputedStyle(editor).lineHeight)||23;editor.scrollTop=Math.max(0,(line-4)*lineHeight);requestAnimationFrame(()=>{const marker=$('sync-highlight');marker.style.top=`${editor.offsetTop+22+(line-1)*lineHeight-editor.scrollTop}px`;marker.hidden=false;clearTimeout(window.syncHighlightTimer);window.syncHighlightTimer=setTimeout(()=>{marker.hidden=true},1800)});sendCursor()}catch(error){$('suggestion').innerHTML=`<div class="suggestion"><strong>PDF 위치 연결 오류</strong><br>${esc(error.message)}</div>`}}
async function renderPdfPreview(binary,synctex){renderedSynctex=synctex;const preview=$('paper-preview');preview.classList.add('pdf-mode');resetPdfPageIndicator();preview.innerHTML='<div class="pdf-loading">PDF 페이지를 준비하고 있습니다…</div>';const pdfjs=await import('/vendor/pdfjs/pdf.mjs');pdfjs.GlobalWorkerOptions.workerSrc='/vendor/pdfjs/pdf.worker.mjs';const pdfDocument=await pdfjs.getDocument({data:binary}).promise;const viewer=document.createElement('div');viewer.className='pdf-canvas-viewer';viewer.style.zoom=String(layout.pdfZoom);preview.replaceChildren(viewer);for(let pageNumber=1;pageNumber<=pdfDocument.numPages;pageNumber+=1){const page=await pdfDocument.getPage(pageNumber);const base=page.getViewport({scale:1});const scale=Math.max(.35,(preview.clientWidth-36)/base.width);const viewport=page.getViewport({scale});const ratio=Math.min(devicePixelRatio||1,2);const wrapper=document.createElement('div');wrapper.className='pdf-page';wrapper.dataset.page=String(pageNumber);const canvas=document.createElement('canvas');canvas.width=Math.floor(viewport.width*ratio);canvas.height=Math.floor(viewport.height*ratio);canvas.style.width=`${viewport.width}px`;canvas.style.height=`${viewport.height}px`;canvas.setAttribute('aria-label',`PDF ${pageNumber}페이지 — 클릭하면 LaTeX 원문으로 이동`);wrapper.append(canvas);viewer.append(wrapper);await page.render({canvasContext:canvas.getContext('2d'),viewport,transform:ratio===1?null:[ratio,0,0,ratio,0,0]}).promise;canvas.onclick=event=>{const rect=canvas.getBoundingClientRect();const displayScale=scale*layout.pdfZoom;syncPdfToSource(pageNumber,(event.clientX-rect.left)/displayScale,(event.clientY-rect.top)/displayScale)}}schedulePdfPageIndicatorUpdate()}
function pdfFileName(){const title=titleOf(state.files['paper/main.tex']||'').replace(/\\[a-zA-Z]+|[{}]/g,' ').replace(/[^\p{L}\p{N}._ -]+/gu,'').trim().replace(/\s+/g,'-').slice(0,80);return `${title||'paper'}.pdf`}
