async function importLocalFiles(entries,targetFolder='paper'){let imported=0;const skipped=[];for(const {file,relativePath} of entries){const relative=cleanRelativePath(relativePath||file.name);if(!relative)continue;if(file.size>assetDataLimit){skipped.push(`${file.name} (2 MB 초과)`);continue;}const destination=uniqueProjectPath(targetFolder?`${targetFolder}/${relative}`:relative);ensureFolderChain(parentPath(destination));const extension=extensionOf(destination);try{if(file.type.startsWith('text/')||textExtensions.has(extension)){state.files[destination]=await file.text();}else{state.assets[destination]={type:file.type||'application/octet-stream',size:file.size,data:await fileToDataUrl(file)};}state.uploads=[...new Set([destination,...state.uploads])];imported+=1;}catch{skipped.push(file.name)}}for(let folder=targetFolder;folder;folder=parentPath(folder))state.collapsedFolders=state.collapsedFolders.filter(item=>item!==folder);listFiles();if(imported)save();if(skipped.length)alert(`가져오지 못한 파일:\n${skipped.join('\n')}`);return imported}
function compilePayload(){const files={};for(const [path,content] of Object.entries(state.files)){if(!path.startsWith('paper/'))continue;const relative=path.slice('paper/'.length);if(compileTextExtensions.has(extensionOf(relative)))files[relative]=content;}files['main.tex']=state.files['paper/main.tex'];const assets={};for(const [path,asset] of Object.entries(state.assets)){if(!path.startsWith('paper/')||!compileAssetExtensions.has(extensionOf(path)))continue;assets[path.slice('paper/'.length)]=asset.data.slice(asset.data.indexOf(',')+1);}return {files,assets}}
let contextTarget={type:'root',path:''};let pendingUploadFolder='';
function showTreeMenu(event,type,path){event.preventDefault();event.stopPropagation();contextTarget={type,path};const menu=$('tree-menu');const protectedPaper=(type==='folder'&&path==='paper')||(type==='file'&&path==='paper/main.tex');menu.querySelector('[data-action="new-folder"]').hidden=type==='file';menu.querySelector('[data-action="upload"]').hidden=type==='file';menu.querySelector('[data-action="rename"]').hidden=type==='root'||protectedPaper;menu.querySelector('[data-action="delete"]').hidden=type==='root'||protectedPaper;menu.hidden=false;const width=184,height=220;menu.style.left=`${Math.min(event.clientX,innerWidth-width-8)}px`;menu.style.top=`${Math.min(event.clientY,innerHeight-height-8)}px`;}
function fileButton(path){const item=$('file-template').content.firstElementChild.cloneNode(true);item.classList.toggle('active',path===state.current);item.querySelector('.file-label').textContent=baseName(path);item.title=path;item.draggable=true;item.onclick=()=>{state.files[state.current]=$('editor').value;state.current=path;$('editor').value=state.files[path];$('active-file').textContent=path;listFiles();save();sendCursor();};item.oncontextmenu=event=>showTreeMenu(event,'file',path);return item}
