function clearDropState(){document.querySelector('.sidebar').classList.remove('file-dragging');document.querySelectorAll('.folder-row.drop-target').forEach(row=>row.classList.remove('drop-target'))}
function folderElement(path,allFolders){const wrapper=document.createElement('div');const collapsed=state.collapsedFolders.includes(path);const row=document.createElement('button');row.className=`folder-row ${collapsed?'':'open'} ${state.activeFolder===path?'selected':''}`;row.title=`${path} 폴더 · 업로드 대상으로 선택`;row.innerHTML=`<span class="folder-chevron">▶</span><svg class="folder-icon" viewBox="0 0 24 20" aria-hidden="true"><path d="M2.5 4.5h7l2 2h10v11h-19z"/></svg><span class="folder-name">${esc(baseName(path))}</span>`;const children=document.createElement('div');children.className=`folder-children ${collapsed?'collapsed':''}`;row.onclick=()=>{state.activeFolder=path;const index=state.collapsedFolders.indexOf(path);if(index<0)state.collapsedFolders.push(path);else state.collapsedFolders.splice(index,1);listFiles();save();};row.oncontextmenu=event=>{state.activeFolder=path;showTreeMenu(event,'folder',path)};row.ondragover=event=>{if(!hasLocalFiles(event))return;event.preventDefault();event.stopPropagation();row.classList.add('drop-target');event.dataTransfer.dropEffect='copy'};row.ondragleave=()=>row.classList.remove('drop-target');row.ondrop=async event=>{if(!hasLocalFiles(event))return;event.preventDefault();event.stopPropagation();clearDropState();state.activeFolder=path;await importLocalFiles(await droppedLocalFiles(event.dataTransfer),path)};[...allFolders].filter(folder=>parentPath(folder)===path).sort().forEach(folder=>children.append(folderElement(folder,allFolders)));Object.keys(state.files).filter(file=>parentPath(file)===path).sort().forEach(file=>children.append(fileButton(file)));Object.keys(state.assets).filter(file=>parentPath(file)===path).sort().forEach(file=>children.append(assetButton(file)));wrapper.append(row,children);return wrapper}
function listFiles(){const files=$('files');files.innerHTML='';const allFolders=new Set(state.folders);for(const file of [...Object.keys(state.files),...Object.keys(state.assets)]){let folder=parentPath(file);while(folder){allFolders.add(folder);folder=parentPath(folder)}}for(const folder of [...state.folders]){let parent=parentPath(folder);while(parent){allFolders.add(parent);parent=parentPath(parent)}}[...allFolders].filter(folder=>!parentPath(folder)).sort((a,b)=>a==='paper'?-1:b==='paper'?1:a.localeCompare(b)).forEach(folder=>files.append(folderElement(folder,allFolders)));Object.keys(state.files).filter(file=>!parentPath(file)).sort().forEach(file=>files.append(fileButton(file)));Object.keys(state.assets).filter(file=>!parentPath(file)).sort().forEach(file=>files.append(assetButton(file)));$('uploaded-files').innerHTML=state.uploads.map(name=>`<div class="source-file">${esc(name)}</div>`).join('')||'<p class="hint">아직 업로드한 자료가 없습니다.</p>'; $('comment-list').innerHTML=state.comments.map(comment=>`<div class="source-file"><b>${esc(comment.anchor)}</b><br>${esc(comment.body)}<br><small>revision ${comment.revision} · 해결</small></div>`).join('')||'<p class="hint">아직 댓글이 없습니다.</p>'}
