function installEditorShortcuts(){document.addEventListener('keydown',event=>{const modifier=event.metaKey||event.ctrlKey;if(!modifier)return;const key=event.key.toLowerCase();if(key==='s'){event.preventDefault();state.files[state.current]=$('editor').value;clearTimeout(window.saveTimer);if(save()){$('save-state').textContent='저장됨';compileAfterSave()}return}if(document.activeElement!==$('editor'))return;if(key==='z'){event.preventDefault();if(event.shiftKey)redoEditor();else undoEditor();return}if(key==='y'){event.preventDefault();redoEditor()}})}
