function activateAssistantTab(id){setAssistantCollapsed(false);document.querySelectorAll('.tab').forEach(tab=>tab.classList.toggle('active',tab.dataset.tab===id));document.querySelectorAll('.assistant-content').forEach(content=>content.classList.toggle('hidden',content.id!==id))}
function applyCodexRevision(selection,replacement){const editor=$('editor');if(selection.file!==state.current||editor.value.slice(selection.start,selection.end)!==selection.text){alert('Codex 요청 이후 원문이 변경되어 자동 적용하지 않았습니다. 다시 선택해 주세요.');return}historyFor(undoHistory,state.current).push(editorSnapshot());historyFor(redoHistory,state.current).length=0;editor.setRangeText(replacement,selection.start,selection.end,'select');activeSelection={file:state.current,start:selection.start,end:selection.start+replacement.length,text:replacement};updateEditorMetadata();hideSelectionToolbar();$('suggestion').querySelector('#apply-codex')?.remove()}
function prepareCodexRequest(){const selection=selectedEditorRange();if(!selection)return;activeSelection=selection;activateAssistantTab('assist');hideSelectionToolbar();const excerpt=selection.text.slice(0,600);$('suggestion').innerHTML=`<div class="selection-anchor"><strong>선택한 문장</strong><div class="latex-preview">${latexPreview(excerpt)}${selection.text.length>600?'…':''}</div></div>`;$('instruction').focus()}
async function requestCodexRevision(selection,instruction){if(!selection){alert('본문에서 수정할 문장을 먼저 선택해 주세요.');return}activateAssistantTab('assist');hideSelectionToolbar();const button=$('ask');button.disabled=true;$('suggestion').innerHTML='<div class="suggestion codex-loading"><strong>Codex가 원고를 검토하고 있습니다…</strong><br>선택 문장과 현재 파일 문맥을 읽기 전용으로 전달했습니다.</div>';try{const response=await fetch('/api/codex',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({file:selection.file,selection:selection.text,instruction,source:state.files[selection.file],actor_id:actor.id})});const result=await response.json();if(!response.ok)throw new Error(result.error||'Codex 요청 실패');$('suggestion').innerHTML=`<div class="suggestion codex-result"><strong>Codex 수정안</strong><div class="latex-preview">${latexPreview(result.replacement)}</div>${result.summary?`<div class="codex-summary">${esc(result.summary)}</div>`:''}<button id="apply-codex">원문에 적용</button></div>`;$('apply-codex').onclick=()=>applyCodexRevision(selection,result.replacement);}catch(error){$('suggestion').innerHTML=`<div class="suggestion"><strong>Codex 연결 오류</strong><br>${esc(error.message)}</div>`}finally{button.disabled=false}}
function installSelectionTools(){const editor=$('editor'),toolbar=$('selection-toolbar');let dragged=false;editor.addEventListener('pointerdown',()=>{dragged=false;hideSelectionToolbar()});editor.addEventListener('pointermove',event=>{if(event.buttons===1){selectionPointer={x:event.clientX,y:event.clientY};if(editor.selectionEnd>editor.selectionStart)dragged=true}});editor.addEventListener('pointerup',event=>{if(dragged&&editor.selectionEnd>editor.selectionStart)captureEditorSelection(event);else hideSelectionToolbar();dragged=false});editor.addEventListener('input',hideSelectionToolbar);editor.addEventListener('scroll',hideSelectionToolbar);toolbar.addEventListener('pointerdown',event=>event.preventDefault());$('selection-comment').onclick=()=>{const selection=selectedEditorRange();if(!selection)return;activateAssistantTab('comments');hideSelectionToolbar();$('comment-body').placeholder=`선택: ${selection.text.slice(0,70)}${selection.text.length>70?'…':''}`;$('comment-body').focus()};$('selection-codex').onclick=prepareCodexRequest;document.addEventListener('pointerdown',event=>{if(event.target!==editor&&!toolbar.contains(event.target))hideSelectionToolbar()})}
let compileQueue=Promise.resolve(),compileRevision=0;
function compileAfterSave(){const revision=++compileRevision;compileQueue=compileQueue.finally(()=>revision===compileRevision?runUpdate():undefined);return compileQueue}
async function runUpdate(){state.files[state.current]=$('editor').value;$('render-state').textContent='PDF 컴파일 중…';try{const response=await fetch('/api/compile',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(compilePayload())});const result=await response.json();if(!response.ok)throw new Error(result.error||'컴파일 실패');const binary=Uint8Array.from(atob(result.pdf_base64),char=>char.charCodeAt(0));setRenderedPdf(binary);await renderPdfPreview(binary,result.synctex_base64||'');$('render-state').textContent=`갱신됨 · ${(result.elapsed_ms/1000).toFixed(1)}초`;save();}catch(error){$('render-state').textContent='컴파일 오류';$('suggestion').innerHTML=`<div class="suggestion"><strong>PDF 컴파일 오류</strong><br>${esc(String(error.message).slice(-900))}</div>`;}}
$('refresh-pdf').onclick=async()=>{const button=$('refresh-pdf');button.classList.add('loading');button.disabled=true;try{await runUpdate()}finally{button.classList.remove('loading');button.disabled=false}};
$('download-pdf').onclick=()=>{if(!renderedPdfUrl)return;const link=document.createElement('a');link.href=renderedPdfUrl;link.download=pdfFileName();document.body.append(link);link.click();link.remove()};
window.addEventListener('pagehide',()=>{if(renderedPdfUrl)URL.revokeObjectURL(renderedPdfUrl)});
function createFile(folder='paper'){const name=cleanSegment(prompt('새 파일 이름','section.tex'));if(!name)return;const path=folder?`${folder}/${name}`:name;if(state.files[path])return alert('같은 이름의 파일이 이미 있습니다.');state.files[path]='% 새 파일';state.current=path;for(let parent=folder;parent;parent=parentPath(parent))state.collapsedFolders=state.collapsedFolders.filter(item=>item!==parent);setEditor();listFiles();save()}
function createFolder(parent=''){const name=cleanSegment(prompt('새 폴더 이름',parent?'results':'experiments'));if(!name)return;const path=parent?`${parent}/${name}`:name;if(state.folders.includes(path))return alert('같은 이름의 폴더가 이미 있습니다.');state.folders.push(path);for(let folder=parent;folder;folder=parentPath(folder))state.collapsedFolders=state.collapsedFolders.filter(item=>item!==folder);listFiles();save()}
function renameTarget(type,path){const name=cleanSegment(prompt('새 이름',baseName(path)));if(!name||name===baseName(path))return;const destination=parentPath(path)?`${parentPath(path)}/${name}`:name;if(type==='file'){if(state.files[destination]||state.assets[destination])return alert('같은 이름의 파일이 이미 있습니다.');state.files[destination]=state.files[path];delete state.files[path];if(state.current===path)state.current=destination;}else if(type==='asset'){if(state.files[destination]||state.assets[destination])return alert('같은 이름의 파일이 이미 있습니다.');state.assets[destination]=state.assets[path];delete state.assets[path];state.uploads=state.uploads.map(item=>item===path?destination:item);}else{if(state.folders.includes(destination))return alert('같은 이름의 폴더가 이미 있습니다.');state.files=Object.fromEntries(Object.entries(state.files).map(([file,content])=>[file===path||file.startsWith(`${path}/`)?destination+file.slice(path.length):file,content]));state.assets=Object.fromEntries(Object.entries(state.assets).map(([file,content])=>[file===path||file.startsWith(`${path}/`)?destination+file.slice(path.length):file,content]));state.uploads=state.uploads.map(item=>item===path||item.startsWith(`${path}/`)?destination+item.slice(path.length):item);state.folders=state.folders.map(folder=>folder===path||folder.startsWith(`${path}/`)?destination+folder.slice(path.length):folder);state.collapsedFolders=state.collapsedFolders.map(folder=>folder===path||folder.startsWith(`${path}/`)?destination+folder.slice(path.length):folder);if(state.current===path||state.current.startsWith(`${path}/`))state.current=destination+state.current.slice(path.length);}setEditor();listFiles();save()}
function deleteTarget(type,path){if(!confirm(`'${baseName(path)}'을(를) 삭제할까요?`))return;if(type==='file')delete state.files[path];else if(type==='asset'){delete state.assets[path];state.uploads=state.uploads.filter(item=>item!==path);}else{state.files=Object.fromEntries(Object.entries(state.files).filter(([file])=>file!==path&&!file.startsWith(`${path}/`)));state.assets=Object.fromEntries(Object.entries(state.assets).filter(([file])=>file!==path&&!file.startsWith(`${path}/`)));state.uploads=state.uploads.filter(item=>item!==path&&!item.startsWith(`${path}/`));state.folders=state.folders.filter(folder=>folder!==path&&!folder.startsWith(`${path}/`));state.collapsedFolders=state.collapsedFolders.filter(folder=>folder!==path&&!folder.startsWith(`${path}/`));}if(!state.files[state.current])state.current=state.files['paper/main.tex']?'paper/main.tex':Object.keys(state.files)[0];setEditor();listFiles();save()}
$('new-file').onclick=()=>createFile(state.activeFolder||'paper');
$('new-folder').onclick=()=>createFolder('');
$('files').oncontextmenu=event=>{if(event.target===$('files'))showTreeMenu(event,'root','')};
let sidebarDragDepth=0;const sidebar=document.querySelector('.sidebar');sidebar.addEventListener('dragenter',event=>{if(!hasLocalFiles(event))return;event.preventDefault();sidebarDragDepth+=1;sidebar.classList.add('file-dragging')});sidebar.addEventListener('dragover',event=>{if(!hasLocalFiles(event))return;event.preventDefault();event.dataTransfer.dropEffect='copy'});sidebar.addEventListener('dragleave',event=>{if(!hasLocalFiles(event))return;sidebarDragDepth=Math.max(0,sidebarDragDepth-1);if(!sidebarDragDepth)clearDropState()});sidebar.addEventListener('drop',async event=>{if(!hasLocalFiles(event))return;event.preventDefault();sidebarDragDepth=0;clearDropState();await importLocalFiles(await droppedLocalFiles(event.dataTransfer),'paper')});
document.addEventListener('click',()=>{$('tree-menu').hidden=true});document.addEventListener('scroll',()=>{$('tree-menu').hidden=true},true);window.addEventListener('blur',()=>{$('tree-menu').hidden=true});
$('tree-menu').onclick=event=>{const action=event.target.dataset.action;if(!action)return;const {type,path}=contextTarget;const folder=type==='folder'?path:type==='file'?parentPath(path):'';if(action==='new-file')createFile(folder);if(action==='new-folder')createFolder(folder);if(action==='upload'){pendingUploadFolder=folder;$('upload').click()}if(action==='rename')renameTarget(type,path);if(action==='delete')deleteTarget(type,path);$('tree-menu').hidden=true;};
$('upload').onchange=async e=>{const folder=pendingUploadFolder||state.activeFolder||'paper';pendingUploadFolder='';await importLocalFiles(Array.from(e.target.files).map(file=>({file,relativePath:file.name})),folder);e.target.value='';};
document.querySelectorAll('.tab').forEach(tab=>tab.onclick=()=>activateAssistantTab(tab.dataset.tab));
$('ask').onclick=()=>{const instruction=$('instruction').value.trim();if(!instruction){$('instruction').focus();return}requestCodexRevision(selectedEditorRange(),instruction)};
$('add-comment').onclick=()=>{const selection=selectedEditorRange();const body=$('comment-body').value.trim();if(!selection||!body){alert('본문에서 문장을 드래그하고 댓글을 입력해 주세요.');return;}state.comments.unshift({anchor:selection.text.slice(0,90),body,file:selection.file,start:selection.start,end:selection.end,revision:Date.now()});$('comment-body').value='';activeSelection=null;listFiles();renderComments();save();};
function validManifestPath(path){return typeof path==='string'&&path.length>0&&path.length<=240&&!path.startsWith('/')&&!path.split('/').some(part=>!part||part==='.'||part==='..')}
async function loadProjectManifest(){const response=await fetch('/project/project.json',{cache:'no-store'});if(!response.ok)throw new Error('project.json을 찾지 못했습니다.');const manifest=await response.json();if(!Array.isArray(manifest.files)||!validManifestPath(manifest.entrypoint||'main.tex'))throw new Error('project.json 형식이 올바르지 않습니다.');for(const item of manifest.files)if(!item||!validManifestPath(item.path)||(item.source&&!validManifestPath(item.source)))throw new Error('project.json에 잘못된 파일 경로가 있습니다.');return {...manifest,entrypoint:manifest.entrypoint||'main.tex',version:String(manifest.version||'unversioned')}}
async function loadProject(){
  try{projectManifest=await loadProjectManifest()}catch(error){$('render-state').textContent='프로젝트 설정 오류';$('suggestion').innerHTML=`<div class="suggestion"><strong>프로젝트를 불러오지 못했습니다.</strong><br>${esc(error.message)}</div>`;return}
  const remoteSources={};
  for(const item of projectManifest.files){
    const name=`paper/${item.path}`;
    const source=item.source||item.path;
    if(item.type==='asset'){
      try{const response=await fetch(`/project/${encodeURI(source)}`,{cache:'no-store'});if(!response.ok)continue;const blob=await response.blob();state.assets[name]={type:blob.type||'application/octet-stream',size:blob.size,data:await fileToDataUrl(blob)}}catch{continue}
    }else{
      const value=await fetchProjectSource(name,`/project/${encodeURI(source)}`);
      if(value)remoteSources[name]=value;
    }
  }
  const remoteMain=remoteSources['paper/main.tex'];
  const localMain=state.files['paper/main.tex'];
  const projectVersionChanged=state.projectVersion!==projectManifest.version;
  const serverManagedProjectFiles=new Set(projectManifest.files.filter(item=>item.managed).map(item=>`paper/${item.path}`));

  if(remoteMain){
    if(!isLatexDocument(localMain)){
      if(typeof localMain==='string'&&localMain.trim()&&!looksLikeHtml(localMain)){ensureFolder('paper/drafts');state.files['paper/drafts/pre-analysis-main.tex']||=localMain;}
      state.files['paper/main.tex']=remoteMain;
      state.current='paper/main.tex';
    }else if(state.serverMainSnapshot&&state.serverMainSnapshot!==remoteMain){
      if(localMain!==state.serverMainSnapshot){ensureFolder('paper/drafts');state.files[`paper/drafts/browser-before-server-sync-${Date.now()}.tex`]=localMain;}
      state.files['paper/main.tex']=remoteMain;
      state.current='paper/main.tex';
    }else if(projectVersionChanged&&localMain!==remoteMain){
      ensureFolder('paper/drafts');
      const previousVersion=state.projectVersion||'browser-draft';
      state.files[`paper/drafts/${previousVersion}.tex`]||=localMain;
      state.files['paper/main.tex']=remoteMain;
      state.current='paper/main.tex';
    }
    state.projectVersion=projectManifest.version;
    state.serverMainSnapshot=remoteMain;
  }

  for(const [name,value] of Object.entries(remoteSources)){
    if(name==='paper/main.tex')continue;
    if(name==='paper/references.bib'){
      state.files[name]=mergeBibliography(state.files[name],value);
      continue;
    }
    const localValue=state.files[name];
    const previousSnapshot=state.serverSourceSnapshots[name];
    const serverChanged=typeof previousSnapshot==='string'&&previousSnapshot!==value;
    const replaceManaged=serverManagedProjectFiles.has(name)&&(projectVersionChanged||serverChanged);
    if(!isProjectSource(name,localValue)||replaceManaged){
      if(isProjectSource(name,localValue)&&localValue!==value){
        ensureFolder('paper/drafts');
        const safeName=baseName(name).replace(/[^A-Za-z0-9._-]/g,'_');
        state.files[`paper/drafts/browser-before-server-sync-${Date.now()}-${safeName}`]=localValue;
      }
      state.files[name]=value;
    }
    if(serverManagedProjectFiles.has(name))state.serverSourceSnapshots[name]=value;
  }
  setEditor();syncProjectTitleFromTex(true);render();listFiles();save();initializeServerBackups();
  if(isLatexDocument(state.files['paper/main.tex']))await runUpdate();
  else{$('render-state').textContent='원고 로드 오류';$('suggestion').innerHTML='<div class="suggestion"><strong>원고를 불러오지 못했습니다.</strong><br>유효한 LaTeX 원고를 유지하고 서버 소스는 적용하지 않았습니다.</div>';}
}
setEditor();installPanelResizers();installZoomControls();installPdfPageIndicator();installEditorShortcuts();installSelectionTools();$('editor').addEventListener('input',()=>{syncProjectTitleFromTex();renderRemoteCursors()});$('editor').addEventListener('scroll',renderRemoteCursors);window.addEventListener('resize',renderRemoteCursors);listFiles();renderComments();render();loadProject();
